"""Unit tests for Project Team Langfuse prompt fetch."""

from __future__ import annotations

import pytest

from agents.project_team.langfuse_prompts import fetch_project_team_prompts


class _FakePrompt:
    def __init__(self, text: str) -> None:
        self.prompt = text


class _FakeClient:
    def __init__(self, mapping: dict[str, str]) -> None:
        self._mapping = mapping

    def get_prompt(
        self,
        name: str,
        *,
        label: str,
        cache_ttl_seconds: int | None = None,
    ) -> object:
        if label != "production":
            raise KeyError(label)
        return _FakePrompt(self._mapping[name])


def test_fetch_project_team_prompts(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            "project-team/leader": "leader body",
            "project-team/design-steward": "steward body",
            "project-team/coder-steward": "coder body",
            "project-team/planner": "planner body",
            "project-team/reimaginer": "reimaginer body",
        }
    )
    prompts = fetch_project_team_prompts(client)
    assert prompts["leader"] == "leader body"
    assert prompts["design_steward"] == "steward body"
    assert prompts["coder_steward"] == "coder body"
    assert prompts["planner"] == "planner body"
    assert prompts["reimaginer"] == "reimaginer body"


def test_fetch_planner_prompt_respects_env_override(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            "project-team/leader": "leader body",
            "project-team/design-steward": "steward body",
            "project-team/coder-steward": "coder body",
            "custom/planner": "custom planner body",
            "project-team/reimaginer": "reimaginer body",
        }
    )
    prompts = fetch_project_team_prompts(
        client,
        planner_langfuse_prompt_name="custom/planner",
    )
    assert prompts["planner"] == "custom planner body"


def test_fetch_propagates_empty_prompt_body(monkeypatch: pytest.MonkeyPatch) -> None:
    monkeypatch.setenv("LANGFUSE_PROMPT_LABEL", "production")
    client = _FakeClient(
        {
            "project-team/leader": "",
            "project-team/design-steward": "",
            "project-team/coder-steward": "",
            "project-team/planner": "",
            "project-team/reimaginer": "",
        }
    )
    with pytest.raises(ValueError, match="has no usable text body"):
        fetch_project_team_prompts(client)

